import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { Course, Lesson, Module, Quiz } from '../../core/models';

/**
 * LearnLoop instructor course editor — manage a course's modules, lessons,
 * quizzes and questions. Loads via ApiService.getCourse(id) in ngOnInit().
 * Add/remove actions call the module/lesson/quiz/question client methods.
 */
@Component({
  selector: 'app-instructor-course-editor',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './instructor-course-editor.component.html',
  styleUrl: './instructor-course-editor.component.css',
})
export class InstructorCourseEditorComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly course = signal<Course | null>({
    id: 'c1',
    title: 'Intro to Web Development',
    description: 'HTML, CSS, and the fundamentals of the browser.',
    modules: [
      {
        id: 'm1',
        courseId: 'c1',
        order: 1,
        title: 'HTML Basics',
        lessons: [
          { id: 'l1', moduleId: 'm1', order: 1, title: 'What is HTML?', content: '' },
          { id: 'l2', moduleId: 'm1', order: 2, title: 'Elements & Tags', content: '' },
        ],
        quizzes: [],
      },
      {
        id: 'm2',
        courseId: 'c1',
        order: 2,
        title: 'Styling with CSS',
        lessons: [{ id: 'l3', moduleId: 'm2', order: 1, title: 'Selectors & Properties', content: '' }],
        quizzes: [{ id: 'q1', moduleId: 'm2', title: 'CSS Fundamentals Quiz', attemptLimit: 1 }],
      },
    ],
  });

  courseId = '';
  newModuleTitle = '';
  // Per-module draft inputs, keyed by module id.
  lessonDrafts: Record<string, string> = {};
  quizDrafts: Record<string, string> = {};

  constructor(private api: ApiService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.courseId = this.route.snapshot.paramMap.get('id') ?? '';
    this.loading.set(true);
    this.error.set(null);
    this.api.getCourse(this.courseId).subscribe({
      next: (course) => {
        this.course.set(course);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load this course. Please try again.');
        this.loading.set(false);
      },
    });
  }

  private patchModules(fn: (mods: Module[]) => Module[]): void {
    const c = this.course();
    if (!c) return;
    this.course.set({ ...c, modules: fn(c.modules ?? []) });
  }

  addModule(): void {
    const title = this.newModuleTitle.trim();
    if (!title) return;
    const order = (this.course()?.modules?.length ?? 0) + 1;
    this.api.createModule(this.courseId, { title, order }).subscribe({ error: () => {} });
    this.patchModules((mods) => [
      ...mods,
      { id: 'm-new-' + mods.length, courseId: this.courseId, order, title, lessons: [], quizzes: [] },
    ]);
    this.newModuleTitle = '';
  }

  removeModule(mod: Module): void {
    this.api.deleteModule(mod.id).subscribe({ error: () => {} });
    this.patchModules((mods) => mods.filter((m) => m.id !== mod.id));
  }

  addLesson(mod: Module): void {
    const title = (this.lessonDrafts[mod.id] ?? '').trim();
    if (!title) return;
    const order = (mod.lessons?.length ?? 0) + 1;
    this.api.createLesson(mod.id, { title, order, content: '' }).subscribe({ error: () => {} });
    const lesson: Lesson = { id: 'l-new-' + order, moduleId: mod.id, order, title, content: '' };
    this.patchModules((mods) =>
      mods.map((m) => (m.id === mod.id ? { ...m, lessons: [...(m.lessons ?? []), lesson] } : m)),
    );
    this.lessonDrafts[mod.id] = '';
  }

  removeLesson(mod: Module, lesson: Lesson): void {
    this.api.deleteLesson(lesson.id).subscribe({ error: () => {} });
    this.patchModules((mods) =>
      mods.map((m) =>
        m.id === mod.id ? { ...m, lessons: (m.lessons ?? []).filter((l) => l.id !== lesson.id) } : m,
      ),
    );
  }

  addQuiz(mod: Module): void {
    const title = (this.quizDrafts[mod.id] ?? '').trim();
    if (!title) return;
    this.api.createQuiz(mod.id, { title, attemptLimit: 1 }).subscribe({ error: () => {} });
    const quiz: Quiz = { id: 'q-new-' + (mod.quizzes?.length ?? 0), moduleId: mod.id, title, attemptLimit: 1 };
    this.patchModules((mods) =>
      mods.map((m) => (m.id === mod.id ? { ...m, quizzes: [...(m.quizzes ?? []), quiz] } : m)),
    );
    this.quizDrafts[mod.id] = '';
  }

  removeQuiz(mod: Module, quiz: Quiz): void {
    this.api.deleteQuiz(quiz.id).subscribe({ error: () => {} });
    this.patchModules((mods) =>
      mods.map((m) =>
        m.id === mod.id ? { ...m, quizzes: (m.quizzes ?? []).filter((q) => q.id !== quiz.id) } : m,
      ),
    );
  }
}
